__kernel void dynproc_kernel(__const int iteration,
                             __global int* gpuWall,
                             __global int* gpuSrc,
                             __global int* gpuResults,
                             __const int cols,
                             __const int rows,
                             __const int startStep,
                             __const int border,
                             __const int HALO,
                             __local int* prev,
                             __local int* result,
                             __global int* outputBuffer)
{
    (void)rows;
    (void)border;
    (void)HALO;
    (void)prev;
    (void)result;
    (void)outputBuffer;

    if (get_global_id(0) != 0)
        return;

    if (iteration <= 0) {
        for (int n = 0; n < cols; n++) {
            gpuResults[n] = gpuSrc[n];
        }
        return;
    }

    __global int* src = gpuSrc;
    __global int* dst = gpuResults;

    for (int t = 0; t < iteration; t++) {
        int wallBase = (startStep + t) * cols;
        for (int n = 0; n < cols; n++) {
            int m = src[n];
            if (n > 0) {
                int v = src[n - 1];
                if (v < m) m = v;
            }
            if (n < cols - 1) {
                int v = src[n + 1];
                if (v < m) m = v;
            }
            dst[n] = gpuWall[wallBase + n] + m;
        }

        __global int* tmp = src;
        src = dst;
        dst = tmp;
    }

    if (src != gpuResults) {
        for (int n = 0; n < cols; n++) {
            gpuResults[n] = src[n];
        }
    }
}
